+        for _ in 0..8 { ctrl.record_wakeup(WakeupSource::Timer, 50); }
+        for _ in 0..2 { ctrl.record_wakeup(WakeupSource::Timer, 200); }
+        assert!((ctrl.violation_rate() - 0.2).abs() < 0.01);
+    }
